import { useQuery, useAction, getTasks, createTask, updateTask } from 'wasp/client/operations'
import { logout } from 'wasp/client/auth'
import { Task } from 'wasp/entities'
import "./Main.css";

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks)
  const createTaskAction = useAction(createTask)
  const updateTaskAction = useAction(updateTask)

  if (isLoading) return 'Loading...'
  if (error) return 'Error: ' + error.message

  const handleCreateTask = async (event: any) => {
    event.preventDefault()
    const description = event.target.description.value
    event.target.reset()
    try {
      await createTaskAction({ description })
    } catch (err: any) {
      window.alert('Error creating task: ' + err.message)
    }
  }

  const handleToggleTask = async (task: Task) => {
    try {
      await updateTaskAction({ id: task.id, isDone: !task.isDone })
    } catch (err: any) {
      window.alert('Error updating task: ' + err.message)
    }
  }

  return (
    <main className="container">
      <h2 className="title">My Todo List</h2>

      <form onSubmit={handleCreateTask}>
        <input name="description" type="text" placeholder="New task" required />
        <button type="submit">Add Task</button>
      </form>

      <ul className="tasks">
        {tasks?.map((task) => (
          <li key={task.id}>
            <input
              type="checkbox"
              checked={task.isDone}
              onChange={() => handleToggleTask(task)}
            />
            <span style={{ textDecoration: task.isDone ? 'line-through' : 'none' }}>
              {task.description}
            </span>
          </li>
        ))}
      </ul>

      <button onClick={logout}>Logout</button>
    </main>
  );
}

